// FunГ§ГЈo para formatar respostas de IA para WhatsApp (converte ** para *)
const formatAIResponse = (text) => {
  if (!text || typeof text !== 'string') return text;
  return text
    .replace(/\*\*\*([^*]+)\*\*\*/g, '*$1*')  // ***text*** -> *text*
    .replace(/\*\*([^*]+)\*\*/g, '*$1*')      // **text** -> *text*
    .replace(/_{2,}([^_]+)_{2,}/g, '_$1_')    // __text__ -> _text_
    .replace(/```[\s\S]*?```/g, '')           // Remove blocos de cГіdigo
    .replace(/`([^`]+)`/g, '$1')              // Remove inline code
    .replace(/^#{1,6}\s+/gm, '')              // Remove headers markdown
    .replace(/\n{3,}/g, '\n\n')               // Limita quebras de linha
    .trim();
};

const writeJsonFile = (filePath, data) => {
  try {
    // ValidaГ§ГЈo de entrada
    if (data === undefined || data === null) {
      console.error(`вқҢ writeJsonFile: Tentativa de salvar dados nulos em ${filePath}`);
      return false;
    }
    
    // Testa se dados sГЈo serializГЎveis
    let jsonString;
    try {
      jsonString = JSON.stringify(data, null, 2);
    } catch (stringifyError) {
      console.error(`вқҢ writeJsonFile: Dados nГЈo serializГЎveis para ${filePath}:`, stringifyError.message);
      return false;
    }
    
    // Valida JSON gerado
    try {
      JSON.parse(jsonString);
    } catch (validateError) {
      console.error(`вқҢ writeJsonFile: JSON invГЎlido gerado para ${filePath}`);
      return false;
    }
    
    ensureDirectoryExists(pathz.dirname(filePath));
    
    // Escreve em arquivo temporГЎrio primeiro (operaГ§ГЈo atГҙmica)
    const tempPath = filePath + '.tmp';
    fs.writeFileSync(tempPath, jsonString, 'utf-8');
    
    // Verifica integridade do arquivo temporГЎrio
    try {
      const writtenContent = fs.readFileSync(tempPath, 'utf-8');
      JSON.parse(writtenContent);
    } catch (verifyError) {
      console.error(`вқҢ writeJsonFile: VerificaГ§ГЈo falhou para ${filePath}`);
      try { fs.unlinkSync(tempPath); } catch (e) {}
      return false;
    }
    
    // Move arquivo temporГЎrio para destino (atГҙmico)
    fs.renameSync(tempPath, filePath);
    return true;
  } catch (error) {
    console.error(`вқҢ Erro ao escrever JSON em ${filePath}:`, error.message);
    // Tenta limpar arquivo temporГЎrio
    try {
      const tempPath = filePath + '.tmp';
      if (fs.existsSync(tempPath)) fs.unlinkSync(tempPath);
    } catch (e) {}
    return false;
  }
};

/**
 * VersГЈo assГӯncrona do writeJsonFile - nГЈo bloqueia o event loop
 * @param {string} filePath - Caminho do arquivo
 * @param {object} data - Dados a serem salvos
 * @returns {Promise<boolean>}
 */
const writeJsonFileAsync = async (filePath, data) => {
  try {
    if (data === undefined || data === null) {
      console.error(`вқҢ writeJsonFileAsync: Tentativa de salvar dados nulos em ${filePath}`);
      return false;
    }
    
    let jsonString;
    try {
      jsonString = JSON.stringify(data, null, 2);
    } catch (stringifyError) {
      console.error(`вқҢ writeJsonFileAsync: Dados nГЈo serializГЎveis para ${filePath}:`, stringifyError.message);
      return false;
    }
    
    // Valida JSON gerado
    try {
      JSON.parse(jsonString);
    } catch (validateError) {
      console.error(`вқҢ writeJsonFileAsync: JSON invГЎlido gerado para ${filePath}`);
      return false;
    }
    
    await fsPromises.mkdir(pathz.dirname(filePath), { recursive: true });
    
    // Escreve em arquivo temporГЎrio primeiro (operaГ§ГЈo atГҙmica)
    const tempPath = filePath + '.tmp';
    await fsPromises.writeFile(tempPath, jsonString, 'utf-8');
    
    // Verifica integridade
    try {
      const writtenContent = await fsPromises.readFile(tempPath, 'utf-8');
      JSON.parse(writtenContent);
    } catch (verifyError) {
      console.error(`вқҢ writeJsonFileAsync: VerificaГ§ГЈo falhou para ${filePath}`);
      try { await fsPromises.unlink(tempPath); } catch (e) {}
      return false;
    }
    
    // Move arquivo temporГЎrio para destino (atГҙmico)
    await fsPromises.rename(tempPath, filePath);
    return true;
  } catch (error) {
    console.error(`вқҢ Erro ao escrever JSON async em ${filePath}:`, error.message);
    try {
      const tempPath = filePath + '.tmp';
      await fsPromises.unlink(tempPath).catch(() => {});
    } catch (e) {}
    return false;
  }
};

/**
 * Leitura assГӯncrona de arquivo JSON
 * @param {string} filePath - Caminho do arquivo
 * @param {object} defaultValue - Valor padrГЈo se arquivo nГЈo existir
 * @returns {Promise<object>}
 */
const readJsonFileAsync = async (filePath, defaultValue = {}) => {
  try {
    const content = await fsPromises.readFile(filePath, 'utf-8');
    return JSON.parse(content);
  } catch (error) {
    if (error.code !== 'ENOENT') {
      console.error(`вқҢ Erro ao ler JSON async de ${filePath}:`, error.message);
    }
    return defaultValue;
  }
};

/**
 * Verifica se arquivo existe (assГӯncrono)
 * @param {string} filePath - Caminho do arquivo
 * @returns {Promise<boolean>}
 */
const fileExistsAsync = async (filePath) => {
  try {
    await fsPromises.access(filePath);
    return true;
  } catch {
    return false;
  }
};

// ==================== PROTEГҮГғO ANTI-BAN: Rate Limit para MenГ§Гөes em Massa ====================
// Sistema controlado pelo dono: pode ativar/desativar proteГ§ГЈo por grupo
const MASS_MENTION_THRESHOLD = 150; // Membros mГӯnimos para aplicar proteГ§ГЈo (quando ativa)
const MASS_MENTION_MAX_USES = 2;    // MГЎximo de usos permitidos
const MASS_MENTION_COOLDOWN = 5 * 60 * 60 * 1000; // 5 horas em milissegundos

// Cache em memГіria para rate limit (persistido em arquivo)
let massMentionLimitCache = null;
let massMentionConfigCache = null;

const loadMassMentionConfig = () => {
  if (massMentionConfigCache) return massMentionConfigCache;
  try {
    if (fs.existsSync(MASS_MENTION_CONFIG_FILE)) {
      massMentionConfigCache = JSON.parse(fs.readFileSync(MASS_MENTION_CONFIG_FILE, 'utf-8'));
    } else {
      massMentionConfigCache = {}; // Vazio = desativado por padrГЈo
    }
  } catch (e) {
    console.error('Erro ao carregar massMentionConfig:', e.message);
    massMentionConfigCache = {};
  }
  return massMentionConfigCache;
};

const saveMassMentionConfig = (data) => {
  massMentionConfigCache = data;
  try {
    ensureDirectoryExists(pathz.dirname(MASS_MENTION_CONFIG_FILE));
    fs.writeFileSync(MASS_MENTION_CONFIG_FILE, JSON.stringify(data, null, 2), 'utf-8');
  } catch (e) {
    console.error('Erro ao salvar massMentionConfig:', e.message);
  }
};

const loadMassMentionLimit = () => {
  if (massMentionLimitCache) return massMentionLimitCache;
  try {
    if (fs.existsSync(MASS_MENTION_LIMIT_FILE)) {
      massMentionLimitCache = JSON.parse(fs.readFileSync(MASS_MENTION_LIMIT_FILE, 'utf-8'));
    } else {
      massMentionLimitCache = {};
    }
  } catch (e) {
    console.error('Erro ao carregar massMentionLimit:', e.message);
    massMentionLimitCache = {};
  }
  return massMentionLimitCache;
};

const saveMassMentionLimit = (data) => {
  massMentionLimitCache = data;
  try {
    ensureDirectoryExists(pathz.dirname(MASS_MENTION_LIMIT_FILE));
    fs.writeFileSync(MASS_MENTION_LIMIT_FILE, JSON.stringify(data, null, 2), 'utf-8');
  } catch (e) {
    console.error('Erro ao salvar massMentionLimit:', e.message);
  }
};

/**
 * Verifica se o grupo pode usar comandos de menГ§ГЈo em massa
 * @param {string} groupId - ID do grupo
 * @param {number} memberCount - NГәmero de membros do grupo
 * @returns {{ allowed: boolean, remainingUses: number, resetTime: number|null, message: string|null }}
 */
const checkMassMentionLimit = (groupId, memberCount) => {
  // Verifica se a proteГ§ГЈo estГЎ ativada para este grupo
  const config = loadMassMentionConfig();
  if (!config[groupId] || !config[groupId].enabled) {
    return { allowed: true, remainingUses: -1, resetTime: null, message: null };
  }
  
  // Se grupo tem menos de 150 membros, nГЈo aplica limite mesmo se ativo
  if (memberCount < MASS_MENTION_THRESHOLD) {
    return { allowed: true, remainingUses: -1, resetTime: null, message: null };
  }

  const data = loadMassMentionLimit();
  const now = Date.now();
  
  // Inicializa dados do grupo se nГЈo existir
  if (!data[groupId]) {
    data[groupId] = { uses: [], lastReset: now };
  }
  
  const groupData = data[groupId];
  
  // Remove usos antigos (mais de 5 horas)
  groupData.uses = groupData.uses.filter(timestamp => (now - timestamp) < MASS_MENTION_COOLDOWN);
  
  // Verifica se atingiu o limite
  if (groupData.uses.length >= MASS_MENTION_MAX_USES) {
    const oldestUse = Math.min(...groupData.uses);
    const resetTime = oldestUse + MASS_MENTION_COOLDOWN;
    const timeLeft = resetTime - now;
    const hours = Math.floor(timeLeft / (60 * 60 * 1000));
    const minutes = Math.floor((timeLeft % (60 * 60 * 1000)) / (60 * 1000));
    
    return {
      allowed: false,
      remainingUses: 0,
      resetTime: resetTime,
      message: `вҡ пёҸ *ProteГ§ГЈo Anti-Ban Ativada pelo Dono*\n\n` +
               `Este grupo tem ${memberCount} membros. Para evitar banimento do nГәmero do bot pela Meta, ` +
               `o dono ativou uma proteГ§ГЈo que limita comandos de marcaГ§ГЈo em massa a *${MASS_MENTION_MAX_USES} usos a cada 5 horas*.\n\n` +
               `вҸ° PrГіximo uso disponГӯvel em: *${hours}h ${minutes}min*`
    };
  }
  
  saveMassMentionLimit(data);
  
  return {
    allowed: true,
    remainingUses: MASS_MENTION_MAX_USES - groupData.uses.length,
    resetTime: null,
    message: null
  };
};

/**
 * Registra um uso de menГ§ГЈo em massa
 * @param {string} groupId - ID do grupo
 */
const registerMassMentionUse = (groupId) => {
  const data = loadMassMentionLimit();
  const now = Date.now();
  
  if (!data[groupId]) {
    data[groupId] = { uses: [], lastReset: now };
  }
  
  // Remove usos antigos antes de adicionar novo
  data[groupId].uses = data[groupId].uses.filter(timestamp => (now - timestamp) < MASS_MENTION_COOLDOWN);
  data[groupId].uses.push(now);
  
  saveMassMentionLimit(data);
};

