          me.ingredients.carne = (me.ingredients.carne || 0) + meatQty;
          
          saveEconomy(econ);
          
          let huntText = `в•ӯв”Ғв”Ғв”ҒвҠұ рҹҸ№ *CAГҮOU!* рҹҸ№ вҠұв”Ғв”Ғв”Ғв•®\n`;
          huntText += `в”Ӯ\n`;
          huntText += `в”Ӯ рҹ’° Ganhou: *${fmt(total)}*\n`;
