        me.investments.totalInvested += totalCost;
        
        let text = `в•ӯв”Ғв”Ғв”ҒвҠұ рҹ’ј *INVESTIMENTO* вҠұв”Ғв”Ғв”Ғв•®\n`;
        text += `в•°в”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв•Ҝ\n\n`;
        text += `вң… Investimento realizado!\n\n`;
        text += `рҹ“Ҡ AГ§ГЈo: ${stockType.toUpperCase()}\n`;
        text += `рҹ“Ҳ Quantidade: ${amount}\n`;
        text += `рҹ’° Valor: ${totalCost.toLocaleString()}\n`;
        text += `рҹ’ј Total investido: ${me.investments.totalInvested.toLocaleString()}`;
        
        saveEconomy(econ);
        return reply(text);
