          const addcmdMidiaHelp = `рҹ“қ *Como usar o comando addcmdmidia:*\n\n1пёҸвғЈ Responda uma mГӯdia (imagem, vГӯdeo, ГЎudio ou figurinha)\n2пёҸвғЈ Use: ${groupPrefix}addcmdmidia <comando> [meta...] <legenda opcional>\n\n*Metatags / Flags suportadas:*\nвҖў [owner] вҖ” Somente o dono do bot pode usar\nвҖў [admin] вҖ” Somente admins do grupo podem usar (somente em grupos)\nвҖў [group] вҖ” Restrito a grupos\nвҖў [private] вҖ” Restrito ao privado\nвҖў [param:type:name:required] вҖ” ParГўmetro posicional\nвҖў [param:type:name:rest] вҖ” Captura resto da mensagem para legenda\nвҖў [param:type:name:min=1:max=10:default=5] вҖ” Min/max/default para nГәmeros\nвҖў [param:regex:name:pattern=^\\\d+$] вҖ” Regex para validar\n\n*Placeholders (na legenda):*\nвҖў {prefixo} - Prefixo do bot\nвҖў {nomedono} - Nome do dono\nвҖў {numerodono} - NГәmero do dono\nвҖў {nomebot} - Nome do bot\nвҖў {user} - Nome do usuГЎrio\nвҖў {grupo} - Nome do grupo\nвҖў {1}, {2}, ... - Argumentos por posiГ§ГЈo (1-based)\nвҖў {args} ou {all} - Todos os argumentos\n\n*Exemplos:*\nвҖў Responder imagem com legenda que usa parГўmetro de arquivo:\n${groupPrefix}addcmdmidia logo [private] [param:string:filename:optional] (responder uma imagem com legenda que aceita {filename})`;
          
