          responseText += `вҖў ${groupPrefix}addcmdmidia <cmd> (com mГӯdia)\n`;
          responseText += `вҖў ${groupPrefix}delcmd <nГәmero>\n`;
          responseText += `вҖў ${groupPrefix}testcmd <cmd>`;
          responseText += `\n\n*Placeholders disponГӯveis para respostas:*
вҖў {args} ou {all} - Todos os argumentos passados apГіs o gatilho
вҖў {1}, {2}, ... - Argumentos por posiГ§ГЈo (1-based)
вҖў {mention} - MenГ§ГЈo ao primeiro usuГЎrio marcado na mensagem
вҖў {mentions} - MenГ§ГЈo a todos os marcados na mensagem
вҖў {quoted} - Texto da mensagem citada (quando houver)`;
          
          await reply(responseText);
