          if (numVencedores < 1 || numGrupos < 1) return reply('вқҢ Quantidade de vencedores ou grupos invГЎlida! Use nГәmeros positivos.');
          let resultado = `рҹҺү *Resultado do Sorteio de Nomes* рҹҺү\n\n`;
