          if (!isGroup) return reply("isso so pode ser usado em grupo рҹ’”");
          let path = pathz.join(GRUPOS_DIR, `${from}.json`);
          // OtimizaГ§ГЈo: Usar cache para leitura de arquivo
          let data = await optimizer.loadJsonWithCache(path, { mark: {} });
          let membros = AllgroupMembers.filter(m => !['0', 'marca'].includes(data.mark[m]));
          if (membros.length < 2) return reply('вқҢ Preciso de pelo menos 2 membros vГЎlidos no grupo para realizar o sorteio!');
          let numVencedores = parseInt(q) || 1;
